CREATE TABLE IF NOT EXISTS admin (                                     admin_id INT PRIMARY KEY AUTO_INCREMENT,                                     admin_email VARCHAR(255) UNIQUE NOT NULL,                                     admin_password_hash VARCHAR(255),                                     admin_role ENUM('restaurant_admin','developer_admin') NOT NULL,                                     created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);CREATE TABLE IF NOT EXISTS user ( -- Add an order history references later                                    user_id INT PRIMARY KEY AUTO_INCREMENT,                                    user_email VARCHAR(255) UNIQUE NOT NULL,                                    user_password_hash VARCHAR(255) NOT NULL,                                    user_phone_number INT(10) UNIQUE NULL,                                    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);CREATE TABLE IF NOT EXISTS dishes ( -- add a category references later                                      dish_id INT PRIMARY KEY AUTO_INCREMENT,                                      name VARCHAR(255) NOT NULL UNIQUE,                                      description VARCHAR(255) NOT NULL,                                      price DECIMAL(5,2) NOT NULL,                                      dietary_info VARCHAR(255) NULL,                                      spice_level INT NULL,                                      image_url VARCHAR(255) NULL,                                      is_available boolean NOT NULL,                                      created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);CREATE TABLE IF NOT EXISTS tables (                                      table_id INT PRIMARY KEY AUTO_INCREMENT,                                      capacity INT NOT NULL,                                      location VARCHAR(255) NOT NULL,                                      is_available BOOLEAN NOT NULL,                                      created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,                                      updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);CREATE TABLE IF NOT EXISTS orders (                                      order_id INT PRIMARY KEY AUTO_INCREMENT,                                      user_id INT NOT NULL,                                      order_date TIMESTAMP DEFAULT CURRENT_TIMESTAMP,                                      status VARCHAR(255) NOT NULL,                                      location VARCHAR(255) NOT NULL,                                      delivery_date DATE NOT NULL,                                      payment_method VARCHAR(255) NOT NULL,                                      payment_status VARCHAR(255) NOT NULL,                                      total_amount DECIMAL(10,2) NOT NULL,                                      updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);CREATE TABLE IF NOT EXISTS order_items (                                           order_item_id INT PRIMARY KEY AUTO_INCREMENT,                                           order_id INT,                                           dish_id INT,                                           quantity INT NOT NULL,                                           price DECIMAL(10,2) NOT NUll,                                           SUBTOTAL DECIMAL(10,2) NOT NUll,                                           FOREIGN KEY (order_id) references orders(order_id),                                           FOREIGN KEY (dish_id) references dishes(dish_id));CREATE TABLE IF NOT EXISTS bookings (                                        booking_id INT PRIMARY KEY AUTO_INCREMENT,                                        user_id INT,                                        table_id INT,                                        booking_date TIMESTAMP DEFAULT CURRENT_DATE,                                        booking_time TIME,                                        number_of_guests INT NOT NULL,                                        status varchar(255) NOT NULL,                                        created_at  TIMESTAMP DEFAULT CURRENT_TIMESTAMP,                                        FOREIGN KEY (user_id) references user(user_id),                                        FOREIGN KEY (table_id) references tables(table_id));